var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"확인해보니 어떤가?","JPN":"どうだ？","ENG":"How did it look when you checked?","TWN":"確認過了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"몇 번을 해봐도 결과는 같아.","JPN":"何度やってみても結果は同じだよ。","ENG":"No matter how many times I run it, the result is the same.","TWN":"我試了好幾次，結果都一樣。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"잠망경으로 탐지할 수 있는 가장 깊은 심도에 아주 희미하게 신성 에너지가 감지되고 있어.","JPN":"潜望鏡で探知できる最も深い深度から、ごく微量の神聖エネルギーが感知されてる。","ENG":"At the deepest range the Periscope can detect, there's a very faint trace of Divinity energy.","TWN":"我用潛望鏡在可探測的最深處感應到微微的神性能量。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그럼 뭔가 있긴 하다는 거지? 잘 됐다.","JPN":"じゃあ何かはあるってことだね？　よかった。","ENG":"So there really is something there? That's good news.","TWN":"那麼確實有東西存在囉？太好了。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"좌표만 파악되면 우물로 거기까지 가면 되는 거잖아?","JPN":"座標さえ分かれば、あとはイドでそこまで行けばいいだけの話でしょ？","ENG":"Once we identify the coordinates, we can just go there through the Well, right?","TWN":"只要找到座標，利用井過去不就好了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야 이놈아, 그렇게 간단한 일이 아니니까 이러고 있지!","JPN":"あのね、そんなに簡単な問題じゃないから困ってるの！","ENG":"Hey, idiot! If it were that simple, we wouldn't be struggling like this!","TWN":"哎，你這傢伙，就是因為事情沒那麼簡單，才會卡在這裡啊！"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"앗, 그런 거야?","JPN":"えっ、そうなの？","ENG":"Ah, is that so?","TWN":"啊，這樣啊？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"꼬리를 엄청 흔들고 있길래 잘 풀리는 줄 알았어.","JPN":"尻尾ブンブン振ってるから、うまくいくのかと思った。","ENG":"You were wagging your tail so much I thought things were going well.","TWN":"我看你尾巴動得那麼厲害，還以為一切順利呢。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"생각이 많아질수록 이렇게 되는 거다. 원래.","JPN":"頭の中が複雑だとこうなるんだよ、もともと。","ENG":"That's what happens when you start thinking too much.","TWN":"原本想越多就越容易這樣。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"넌 왜 내 꼬릴 만지는 거냐!","JPN":"あなた、どうして私の尻尾を触るわけ！？","ENG":"And why are you touching my tail?!","TWN":"你為什麼要碰我的尾巴！"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"실례했네. 줄곧 신경이 쓰여서.","JPN":"失礼。ずっと気になっていたのでな。","ENG":"My apologies. It kept catching my attention.","TWN":"抱歉啦，我一直很在意。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"여하튼, 문제는 우리가 우물로 연결할 수 있는 과거의 깊이가 에너지 연료에 비례한다는 걸세.","JPN":"とにかく、問題はイドに繋げる過去の深さが、エネルギー燃料の量に比例するということなのだ。","ENG":"In any case, the problem is that the depth of the past we can connect to through the Well is proportional to the amount of energy fuel we have.","TWN":"總之問題在於我們能利用井連接的過去深度，和能量燃料成正比。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"10년 전, 20년 전이라면 이터니움으로 어떻게든 충당해볼 수 있겠지만...","JPN":"10年前、20年前の過去ならエタニウムでどうにか補充できるが……","ENG":"Ten years, twenty years back... we might manage that with Eternium somehow...","TWN":"如果是10年前、20年前，還能勉強用永恆之金補充……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"단위조차 가늠할 수 없는 영겁의 세월을 우물로 연결하는 건 불가능에 가까워.","JPN":"単位ですら見当もつかない永劫の時間をイドで繋ぐことは限りなく不可能であろう。","ENG":"But connecting the Well to an era stretching across an immeasurable eternity is close to impossible.","TWN":"要連接連單位都無法估算的永恆歲月，幾乎不可能。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"단위조차 정의할 수 없다고...?","JPN":"単位すら定義できないだって……？","ENG":"An era whose units can't even be defined...?","TWN":"連單位都無法定義……？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 곳에 숨어있는 타기리온이란 녀석은 도대체 얼마나 오래된 존재라는 거지?","JPN":"そんなところに隠れてるタギリオンって奴は、いったいどれだけの時を生きているんだ？","ENG":"Just how ancient is this Thagirion who's hiding there?","TWN":"躲在那裡的塔基里翁，到底是個多久遠的存在？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그녀가 존재해온 세월은 부숴온 세계의 숫자에 정비례한다네.","JPN":"彼女が存在してきた時間は、壊してきた世界の数に比例する。","ENG":"The time she has existed is directly proportional to the number of worlds she has destroyed.","TWN":"她存在的歲月，和她毀掉的世界數量成正比。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"많은 세계가 만들어지고 부서지길, 몇 번이나 반복해온 시간일 테지.","JPN":"たくさんの世界が作られては壊れることを幾度となく繰り返してきた時間となるはずだ。","ENG":"It must be a span of time in which countless worlds were created and shattered over and over again.","TWN":"世界被創造、毀滅的過程，不知道重複了多少次。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그런 무한대에 가까운 시간을 거스르는 양자터널을 유지하려면, 그와 비례하는 동력원이 공급되어야만 하지.","JPN":"そんな無限大に近い時間を遡る量子トンネルを維持するには、それに比例する動力源を供給しないといけない。","ENG":"To maintain a quantum tunnel that goes against a span of time approaching infinity, you'd need a power source proportional to it.","TWN":"要維持這近乎無限的量子隧道，需要與之成正比的動力源。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 세상의 이터니움을 전부 모아도 충분하지 않을 거다.","JPN":"この世界のエタニウムを全部集めたって足りないはずだよ。","ENG":"Even if we gathered all the Eternium in this world, it wouldn't be enough.","TWN":"就算收集這世界所有的永恆之金也不夠用。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"세상 모든 이터니움을 모아도 안되는 일이라...","JPN":"世界中のエタニウムを集めても不可能なことか……","ENG":"Not even all the Eternium in the world would do it...","TWN":"就算收集世上所有永恆之金也做不到啊……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 단념하는 수 밖에 없겠네. 종말까지 소중한 사람들과 남은 시간을 보내면서 말이야.","JPN":"じゃあ、諦めるしかないね。終末まで大切な人たちと残りの時間を過ごすことにするよ。","ENG":"Then I suppose the only choice left is to give up. Spend what time remains until the end with the people we care about.","TWN":"那就只能放棄了呢。珍惜末日前和重要的人度過的時間吧。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"쉽게 포기하는군. 애초에 찾을 거란 희망은 가지지도 않았던 것처럼.","JPN":"簡単に諦めてしまうんだな。そもそも見つかるという希望すら持っていなかったかのように。","ENG":"You give up easily. As if you never believed you'd find her in the first place.","TWN":"真容易放棄啊，好像從一開始就沒抱希望一樣。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신들 아니었으면 난 어차피 이면세계에 갇혀 죽을 신세였으니까.","JPN":"あなたたちがいなかったら、私はどうせ裏世界に閉じ込められて死ぬ運命だったんだ。","ENG":"If it weren't for you, I would've died trapped in the Counterside anyway.","TWN":"反正如果不是你們，我也會被困在異界死掉。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 사람이 어떻게 인류 존속이 걸린 중대사를 논하겠어.","JPN":"そんな人間が人類の存続がかかってる問題にどうこう言う権利なんかないだろう。","ENG":"Someone like me has no right to debate a matter that determines humanity's survival.","TWN":"這種人怎麼可能討論與人類存亡有關的大事。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 말씀은, 괜찮은 제안이 있지만 입장을 생각해서 말하지 않겠다는 걸로 들리는데요.","JPN":"その言い方は、いい案があるけど立場をわきまえて言わないって意味に聞こえますけど。","ENG":"What you're saying sounds like you have a viable suggestion, but you won't voice it because of your position.","TWN":"你的意思是雖然有好的提案，但考慮到立場而不說嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아이디어가 있다면 한 번 들어봐도 될까요?","JPN":"アイデアがあるなら、聞かせてくれませんか？","ENG":"If you have an idea, may we hear it?","TWN":"如果有想法，我能聽聽看嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"위험해. 실패하면 전부 죽어.","JPN":"危険だ。失敗したら全員死ぬことになる。","ENG":"It's dangerous. If it fails, we all die.","TWN":"很危險。失敗的話大家都會死。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어차피 이대로라면 인류는 종말을 맞을 거다.","JPN":"どうせこのままだと人類は終末を迎えることになる。","ENG":"If things continue like this, humanity will face extinction anyway.","TWN":"反正照現在這樣下去，人類注定滅亡。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"뭐라도 해보느냐, 아무것도 하지 않은 채 끝나느냐의 차이일 뿐이지.","JPN":"足掻くか、何もしないまま終わるかの違いしかない。","ENG":"The only difference is whether we try something or do nothing and let it end.","TWN":"只是差在要賭賭看，還是什麼都不做的差別而已。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희 사장님께선 인류를 위해 무엇이든 할 용의가 있으신 분이랍니다.","JPN":"うちの社長は人類のためなら何でもやろうとする方なんです。","ENG":"Boss is someone willing to do anything for humanity.","TWN":"我們老闆，願意為了人類做任何事。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그게 설령 우리 모두의 목숨이 걸린 도박이라 하더라도 말이죠.","JPN":"それがたとえ僕たちの命をかけたギャンブルだとしてもです。","ENG":"Even if it means gambling all of our lives.","TWN":"即便是賭上我們所有人的生命也在所不惜。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부정하지 않겠네.</color>","JPN":"<color=#ffd34c>否定はしない。</color>","ENG":"<color=#ffd34c>I won't deny that.</color>","TWN":"<color=#ffd34c>我不否認。</color>"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};